import { expect, test, describe, vi } from "vitest";
import { recoverAudioViaPneuma } from "../audio-pneuma-bridge";

// Mock the bitwise dependencies since they might not be fully available in this environment
vi.mock("@a0n/bitwise/voice-flac-pipeline", () => ({
  encodeVoiceFlacFromSource: vi.fn().mockResolvedValue(new Uint8Array([1, 2, 3])),
  decodeVoiceFlacToSource: vi.fn().mockResolvedValue({ pcm: new Int16Array(1000), sampleRate: 16000 }),
  floatPcmToInt16: vi.fn((f) => new Int16Array(f.length)),
  int16PcmToFloat: vi.fn((i) => new Float32Array(i.length)),
  makeZeroPredictor: vi.fn(() => vi.fn().mockResolvedValue(new Float32Array(1000))),
}));

vi.mock("@a0n/bitwise/voice-flac-codec", () => ({
  inspectVoiceFlac: vi.fn().mockReturnValue({ hasResidual: true, hasProsody: true }),
}));

describe("Audio Pneuma Bridge — Phoneme Fingerprint Integration", () => {
  test("recoverAudioViaPneuma extracts phonemes via the 8-band fingerprint", async () => {
    const audio = new Float32Array(1000).fill(0.1);
    const sampleRate = 16000;

    const result = await recoverAudioViaPneuma({
      audio,
      sampleRate,
      preDenoise: false
    });

    expect(result.audio).toBeDefined();
    expect(result.packetSize).toBeGreaterThan(0);
    // The new bridge always emits a non-empty phoneme stream — either
    // `extractPhonemeFingerprints.frames.length` for audio >= nFft, or
    // a single silence ID as a fallback for shorter buffers.
    expect(result.phonemeIdsExtracted).toBeGreaterThan(0);
    expect(Number.isFinite(result.phonemeIdsExtracted)).toBe(true);
    expect(Number.isInteger(result.phonemeIdsExtracted)).toBe(true);
  });
});
